@DomainEvent
public record OrderLineItemAdded(
    String orderId,
    String productId,
    int quantity,
    Instant occurredAt
) {}

// Order Service publishes this event after saving the order aggregate
orderEventPublisher.publish(new OrderLineItemAdded(
