use std::rc::Rc;
let shared = Rc::new(vec![1, 2, 3]);
let clone1 = Rc::clone(&shared);  // cheap — increments refcount
// let _ = thread::spawn(move || { clone1; });  // COMPILE ERROR: Rc is not Send

// Arc<T>: shared ownership, multi-thread safe
